function addCodeBlockHighlighting(){hljs.highlightAll()}function attachFilePathsToCodeBlocks(){let t=document.querySelectorAll("p");t.forEach(function(t){t.nextElementSibling?.nodeName==="PRE"&&1===t.childNodes.length&&t.childNodes[0]?.nodeName==="CODE"&&(t.classList.add("collapse"),t.childNodes[0].classList.add("codeblock-filepath"))})}function setLinkAttrs(){let t=document.querySelectorAll("a");t.forEach(t=>{let o=t.getAttribute("href");o.startsWith("/")||t.setAttribute("target","_blank")})}function addAnchors(){anchors.add("h2:not(.no-anchor), h3:not(.no-anchor), h4:not(.no-anchor), h5:not(.no-anchor)")}document.addEventListener("DOMContentLoaded",function(t){addCodeBlockHighlighting(),attachFilePathsToCodeBlocks(),setLinkAttrs(),addAnchors()});